func divide(a, b float64) (float64, error) {
    if b == 0 {
        return 0, fmt.Errorf("division by zero")
    }
    return a / b, nil
}

func main() {
    result, err := divide(10, 3)
    if err != nil {
        fmt.Println(err)
    } else {
        fmt.Printf("%.2f\n", result)  // 3.33
    }

    _, err2 := divide(5, 0)
    fmt.Println(err2)  // division by zero
}

